import React from "react";
import { Link } from "react-router-dom";
import { FileText, BarChart3, History, Building2, TrendingUp } from "lucide-react";

const Dashboard = () => {
  const features = [
    {
      title: "Modulo A: Facturacion General",
      description:
        "Extrae datos de facturas: proveedor, RIF, fecha, periodo, subtotal, IVA, monto total, moneda y tipo.",
      icon: FileText,
      link: "/module-a",
      color: "#0033CC",
      testId: "card-module-a",
    },
    {
      title: "Modulo B: Analisis Especializado",
      description:
        "Procesa documentos complejos: ventas de terceros, telefonia movil, rentas y servicios, resumen de consumo.",
      icon: BarChart3,
      link: "/module-b",
      color: "#16A34A",
      testId: "card-module-b",
    },
    {
      title: "Historial de Documentos",
      description:
        "Revisa todos los documentos procesados anteriormente y sus datos extraidos.",
      icon: History,
      link: "/history",
      color: "#EAB308",
      testId: "card-history",
    },
    {
      title: "Centros de Costo",
      description:
        "Gestiona centros de costo y asigna lineas para el analisis detallado.",
      icon: Building2,
      link: "/cost-centers",
      color: "#DC2626",
      testId: "card-cost-centers",
    },
  ];

  return (
    <div className="space-y-6">
      <div className="bg-white border border-zinc-200 rounded-none p-8">
        <div className="flex items-start justify-between">
          <div>
            <h1 className="font-heading text-4xl font-bold text-[#09090B] tracking-tight mb-3">
              Sistema de Extraccion Inteligente de Datos
            </h1>
            <p className="text-lg text-zinc-600 leading-relaxed max-w-3xl">
              Procesa documentos de facturacion y archivos complejos usando Gemini 2.5
              Flash con validaciones previas y un flujo de extraccion consistente.
            </p>
          </div>
          <TrendingUp className="w-16 h-16 text-[#0033CC]" strokeWidth={1.5} />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {features.map((feature) => {
          const Icon = feature.icon;
          return (
            <Link
              key={feature.link}
              to={feature.link}
              data-testid={feature.testId}
              className="bg-white border border-zinc-200 rounded-none p-6 hover:border-[#0033CC] transition-colors group"
            >
              <div className="flex items-start gap-4">
                <div className="p-3 bg-zinc-50 border border-zinc-200">
                  <Icon className="w-6 h-6" style={{ color: feature.color }} strokeWidth={1.5} />
                </div>
                <div className="flex-1">
                  <h3 className="font-heading text-lg font-bold text-[#09090B] mb-2 group-hover:text-[#0033CC] transition-colors">
                    {feature.title}
                  </h3>
                  <p className="text-sm text-zinc-600 leading-relaxed">
                    {feature.description}
                  </p>
                </div>
              </div>
            </Link>
          );
        })}
      </div>
    </div>
  );
};

export default Dashboard;
